  1	import * as React from 'react';
  2	import { LSO_OPERATOR } from '@odf/core/constants';
  3	import {
  4	  useGetExternalClusterDetails,
  5	  useGetInternalClusterDetails,
  6	} from '@odf/core/redux/utils';
  7	import { isCapacityAutoScalingAllowed, getResourceInNs } from '@odf/core/utils';
  8	import OCSSystemDashboard from '@odf/ocs/dashboards/ocs-system-dashboard';
  9	import {
 10	  CustomKebabItem,
 11	  DEFAULT_INFRASTRUCTURE,
 12	  getName,
 13	  getNamespace,
 14	  InfrastructureKind,
 15	  InfrastructureModel,
 16	  Kebab,
 17	  PageHeading,
 18	  StorageClusterKind,
 19	  StorageClusterModel,
 20	  useCustomTranslation,
 21	  useFetchCsv,
 22	  useK8sGet,
 23	} from '@odf/shared';
 24	import {
 25	  getInfrastructurePlatform,
 26	  isCSVSucceeded,
 27	  referenceForModel,
 28	} from '@odf/shared/utils';
 29	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 30	import { TFunction } from 'react-i18next';
 31	import {
 32	  EmptyState,
 33	  EmptyStateBody,
 34	  EmptyStateHeader,
 35	  EmptyStateIcon,
 36	} from '@patternfly/react-core';
 37	import { CubesIcon } from '@patternfly/react-icons';
 38	import InitialEmptyStatePage from './InitialEmptyStatePage';
 39	
 40	const storageClusterActions =
 41	  (
 42	    t: TFunction,
 43	    storageCluster: StorageClusterKind,
 44	    infrastructure: InfrastructureKind,
 45	    isLSOInstalled: boolean,
 46	    isExternalMode: boolean
 47	  ) =>
 48	  () => {
 49	    const resourceProfile = storageCluster?.spec?.resourceProfile;
 50	    const platform = getInfrastructurePlatform(infrastructure);
 51	    const customKebabItems: CustomKebabItem[] = [];
 52	    if (!isExternalMode) {
 53	      customKebabItems.push({
 54	        key: 'ADD_CAPACITY',
 55	        value: t('Add Capacity'),
 56	        component: React.lazy(
 57	          () => import('../../modals/add-capacity/add-capacity-modal')
 58	        ),
 59	      });
 60	      customKebabItems.push({
 61	        key: 'CONFIGURE_PERFORMANCE',
 62	        value: t('Configure performance'),
 63	        component: React.lazy(
 64	          () =>
 65	            import(
 66	              '@odf/core/modals/configure-performance/configure-performance-modal'
 67	            )
 68	        ),
 69	      });
 70	      if (isCapacityAutoScalingAllowed(platform, resourceProfile)) {
 71	        customKebabItems.push({
 72	          key: 'CAPACITY_AUTOSCALING',
 73	          value: t('Automatic capacity scaling'),
 74	          component: React.lazy(
 75	            () =>
 76	              import(
 77	                '@odf/core/modals/capacity-autoscaling/capacity-autoscaling-modal'
 78	              )
 79	          ),
 80	        });
 81	      }
 82	      if (isLSOInstalled) {
 83	        customKebabItems.push({
 84	          key: 'ATTACH_STORAGE',
 85	          value: t('Attach Storage'),
 86	          redirect: `/odf/system/ns/${getNamespace(storageCluster)}/${referenceForModel(
 87	            StorageClusterModel
 88	          )}/${getName(storageCluster)}/~attachstorage`,
 89	        });
 90	      }
 91	    }
 92	    return (
 93	      <Kebab
 94	        extraProps={{
 95	          resource: storageCluster,
 96	          resourceModel: StorageClusterModel,
 97	          storageCluster,
 98	        }}
 99	        customKebabItems={customKebabItems}
100	        toggleType="Dropdown"
101	        customLabel={StorageClusterModel.label}
102	      />
103	    );
104	  };
105	
106	const useInternalStorageCluster = () => {
107	  const [storageClusters] = useK8sWatchResource<StorageClusterKind[]>({
108	    kind: referenceForModel(StorageClusterModel),
109	    isList: true,
110	  });
111	
112	  const internalClusterDetails = useGetInternalClusterDetails();
113	  const currentStorageCluster = getResourceInNs(
114	    storageClusters,
115	    internalClusterDetails.clusterNamespace
116	  ) as StorageClusterKind;
117	  const hasMultipleStorageClusters = storageClusters?.length > 1;
118	
119	  return {
120	    hasMultipleStorageClusters,
121	    selectedCluster: { ...internalClusterDetails, isExternalMode: false },
122	    currentStorageCluster,
123	  };
124	};
125	
126	const StorageClusterSection: React.FC = () => {
127	  const { t } = useCustomTranslation();
128	
129	  const { selectedCluster, hasMultipleStorageClusters, currentStorageCluster } =
130	    useInternalStorageCluster();
131	  const [lsoCSV, lsoCSVLoaded, lsoCSVLoadError] = useFetchCsv({
132	    specName: LSO_OPERATOR,
133	  });
134	  const [infrastructure] = useK8sGet<InfrastructureKind>(
135	    InfrastructureModel,
136	    DEFAULT_INFRASTRUCTURE
137	  );
138	
139	  const externalClusterDetails = useGetExternalClusterDetails();
140	  const isLSOInstalled =
141	    lsoCSVLoaded && !lsoCSVLoadError && isCSVSucceeded(lsoCSV);
142	
143	  const hasExternalMode = externalClusterDetails.clusterName !== '';
144	  const hasInternalMode = selectedCluster.clusterName !== '';
145	  const noStorageClusters = !hasExternalMode && !hasInternalMode;
146	
147	  return noStorageClusters ? (
148	    <InitialEmptyStatePage />
149	  ) : hasExternalMode && !hasInternalMode && !hasMultipleStorageClusters ? (
150	    <ExternalClusterPresentMessage />
151	  ) : (
152	    <>
153	      <PageHeading
154	        title={t('Storage cluster')}
155	        actions={storageClusterActions(
156	          t,
157	          currentStorageCluster,
158	          infrastructure,
159	          isLSOInstalled,
160	          hasExternalMode
161	        )}
162	      />
163	      <OCSSystemDashboard />
164	    </>
165	  );
166	};
167	
168	const ExternalClusterPresentMessage: React.FC = () => {
169	  const { t } = useCustomTranslation();
170	  return (
171	    <EmptyState isFullHeight>
172	      <EmptyStateHeader
173	        titleText={t('Internal mode cluster not available')}
174	        headingLevel="h4"
175	        icon={<EmptyStateIcon icon={CubesIcon} />}
176	      />
177	      <EmptyStateBody>
178	        {t(
179	          'Internal mode cluster setup path is unavailable because an External mode cluster has already been configured.'
180	        )}
181	      </EmptyStateBody>
182	    </EmptyState>
183	  );
184	};
185	
186	export default StorageClusterSection;

